const _cfgPath = global.get('CONFIG_PATH');
function _readCfg() {
  try { return JSON.parse(_fs.readFileSync(_cfgPath, 'utf8')); }
  catch(e) { return { slaveIds: [], activeSlaveIds: [], deviceSettings: {} }; }
}

// Reconnection scanner — polls devices in slaveIds that are NOT in activeSlaveIds
const cfg = _readCfg();
const slaveIds = (cfg.slaveIds || []).map(Number);
const activeSet = new Set((cfg.activeSlaveIds || []).map(Number));
const offlineAdded = slaveIds.filter(id => !activeSet.has(id));

if (offlineAdded.length === 0) return null;

// Round-robin through offline devices
let bgQueue = flow.get('bgScanQueue') || [];
const bgSet = new Set(bgQueue);
offlineAdded.forEach(id => { if (!bgSet.has(id)) bgQueue.push(id); });
if (bgQueue.length === 0) return null;

const slaveId = bgQueue.shift();
flow.set('bgScanQueue', bgQueue);

return [{
    payload: { value: 0, unitid: slaveId, fc: 3, address: 0, quantity: 1 },
    slaveId: slaveId,
    scanType: 'slow',
    isRecoveryAttempt: true
}];

const _cfgPath = global.get('CONFIG_PATH');
function _readCfg() {
  try { return JSON.parse(_fs.readFileSync(_cfgPath, 'utf8')); }
  catch(e) { return { slaveIds: [], activeSlaveIds: [], deviceSettings: {} }; }
}
function _saveCfg(c) {
  try { _fs.writeFileSync(_cfgPath, JSON.stringify(c, null, 2), 'utf8'); }
  catch(e) { node.warn('cfg write error: ' + e.message); }
}
let slaveId = (msg.modbusRequest && msg.modbusRequest.unitid) ||
    (msg.payload && msg.payload.unitid) ||
    (msg.payload && msg.payload.modbusRequest && msg.payload.modbusRequest.unitid) ||
    msg.slaveId || null;

if (!slaveId) { node.warn('OFFLINE: slaveId not found'); return null; }

const OFFLINE_TIMEOUT_MS = 5000;
let lastResponseTime = flow.get(`lastResponseTime_${slaveId}`) || 0;
let currentTime = Date.now();
let isCurrentlyMarkedOffline = flow.get(`isOffline_${slaveId}`) || false;

if ((currentTime - lastResponseTime) <= OFFLINE_TIMEOUT_MS) return null;
if (isCurrentlyMarkedOffline) return null;

flow.set(`isOffline_${slaveId}`, true);

const cfg = _readCfg();
const device = (cfg.deviceSettings || {})['slave_' + slaveId] || { Destination: '', LSP: 0, HSP: 70 };
let tableData = flow.get('tableData', 'file') || {};

tableData['slave_' + slaveId] = {
    ID: slaveId,
    Destination: device.Destination || '',
    TempValue: '-',
    LSP: device.LSP,
    HSP: device.HSP,
    notifyEmail: device.notifyEmail || '',
    Alarm: 'OFFLINE',
    Status: 'OFFLINE',
    lastSeen: tableData['slave_' + slaveId]?.lastSeen || 0
};
flow.set('tableData', tableData, 'file');

const slaveIdNum = Number(slaveId);
const activeIds = (cfg.activeSlaveIds || []).map(Number);
if (activeIds.includes(slaveIdNum)) {
    cfg.activeSlaveIds = activeIds.filter(id => id !== slaveIdNum);
    _saveCfg(cfg);
}

node.warn(`[Marked OFFLINE] Slave ${slaveId} — no response for ${Math.round((currentTime - lastResponseTime)/1000)}s`);

const SLAVE_IDS = cfg.slaveIds || [];
msg.payload = SLAVE_IDS.map(id => tableData['slave_' + id] || {
    ID: id, Destination: '', TempValue: '-',
    LSP: 0, HSP: 70, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0
});

const lastUIUpdate = flow.get('lastUIUpdate') || 0;
const now2 = Date.now();
if (now2 - lastUIUpdate < 1000) return null;
flow.set('lastUIUpdate', now2);
return msg;

if (!msg._logEntry) return null;

const e = msg._logEntry;

if (typeof e.slaveId === 'undefined' || typeof e.tempValue === 'undefined') {
    node.warn("[dp_log] Missing slaveId or tempValue");
    return null;
}

const dt = new Date(e.ts);

if (isNaN(dt.getTime())) {
    node.warn(`[dp_log] Invalid timestamp received: ${e.ts}`);
    return null;
}

const year = dt.getFullYear();
const month = String(dt.getMonth() + 1).padStart(2, '0');
const day = String(dt.getDate()).padStart(2, '0');
const hours = String(dt.getHours()).padStart(2, '0');
const minutes = String(dt.getMinutes()).padStart(2, '0');
const seconds = String(dt.getSeconds()).padStart(2, '0');

const ts = `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;

const slaveId = Number(e.slaveId);
const tempValue = Number(e.tempValue);
const alarm = (e.alarm || 'NORMAL').replace(/'/g, "''");

const dpValue = Number(e.tempValue);

msg.topic = `INSERT INTO dp_log (slave_id, dp_value, alarm_status, logged_at) 
             VALUES (${slaveId}, ${dpValue}, '${alarm}', '${ts}')`;

msg.payload = {};

return msg;

const _cfgPath = global.get('CONFIG_PATH');
function _readCfg() {
  try { return JSON.parse(_fs.readFileSync(_cfgPath, 'utf8')); }
  catch(e) { return { slaveIds: [], activeSlaveIds: [], deviceSettings: {} }; }
}
function _saveCfg(c) {
  try { _fs.writeFileSync(_cfgPath, JSON.stringify(c, null, 2), 'utf8'); }
  catch(e) { node.warn('cfg write error: ' + e.message); }
}
if (!msg.payload) return null;
if (msg.payload.action === 'contacts-result') return msg;
if (msg.payload.action === 'email-config-result') return msg;
if (msg.payload.action === 'change-password-result') return msg;
if (msg.payload.action !== 'set-active-ids') return null;

const rawInput = (msg.payload.raw || '').trim();
const ids = new Set();

rawInput.split(',').forEach(part => {
    part = part.trim();
    const rangeMatch = part.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
        const from = parseInt(rangeMatch[1]), to = parseInt(rangeMatch[2]);
        for (let i = from; i <= to && i <= 200; i++) ids.add(i);
    } else {
        const n = parseInt(part);
        if (!isNaN(n) && n >= 1 && n <= 200) ids.add(n);
    }
});

const sorted = Array.from(ids).sort((a, b) => a - b);
const cfg = _readCfg();
const previousActiveIds = (cfg.activeSlaveIds || []).map(Number);

cfg.slaveIds = sorted;
cfg.activeSlaveIds = sorted;
_saveCfg(cfg);

flow.set('rrIndex', 0);
flow.set('bgScanQueue', []);

let tableData = flow.get('tableData', 'file') || {};
const settings = cfg.deviceSettings || {};

for (let id of sorted) {
    const device = settings['slave_' + id] || { Destination: '', LSP: 0, HSP: 70 };
    if (!tableData['slave_' + id]) {
        tableData['slave_' + id] = {
            ID: id, Destination: device.Destination || '',
            TempValue: '-', LSP: device.LSP, HSP: device.HSP,
            notifyEmail: device.notifyEmail || '',
            Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0
        };
    } else {
        tableData['slave_' + id].TempValue = '-';
        tableData['slave_' + id].Status = 'OFFLINE';
        tableData['slave_' + id].Alarm = 'OFFLINE';
        tableData['slave_' + id].lastSeen = 0;
    }
}
flow.set('tableData', tableData, 'file');

for (let id of ids) {
    flow.set(`isOffline_${id}`, false);
    flow.set(`lastResponseTime_${id}`, 0);
}
for (let id of previousActiveIds) {
    if (!ids.has(id)) {
        flow.set(`isOffline_${id}`, false);
        flow.set(`lastResponseTime_${id}`, 0);
    }
}

msg.payload = sorted.map(id => tableData['slave_' + id] || {
    ID: id, Destination: '', TempValue: '-',
    LSP: 0, HSP: 70, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0
});
return msg;

if (!msg.payload || msg.payload.action !== 'auth-check') return null;
const ADMIN_ID = 'Jetpace';
const ADMIN_PASS = 'Jetpace';
const now = Date.now();
const lockUntil = flow.get('authLockUntil') || 0;
if (now < lockUntil) { const secsLeft = Math.ceil((lockUntil - now) / 1000); msg.payload = { action: 'auth-result', success: false, locked: true, secsLeft }; return msg; }
const enteredId = (msg.payload.userId || '').trim();
const enteredPass = (msg.payload.password || '').trim();
if (enteredId === ADMIN_ID && enteredPass === ADMIN_PASS) { flow.set('authFailCount', 0); flow.set('authLockUntil', 0); msg.payload = { action: 'auth-result', success: true }; }
else { let fails = (flow.get('authFailCount') || 0) + 1; flow.set('authFailCount', fails); if (fails >= 3) { flow.set('authLockUntil', now + 60*1000); flow.set('authFailCount', 0); msg.payload = { action: 'auth-result', success: false, locked: true, secsLeft: 60 }; } else { msg.payload = { action: 'auth-result', success: false, locked: false, attemptsLeft: 3 - fails }; } }
return msg;

if (!msg.payload || msg.payload.action !== 'report-query') return null;

const p = msg.payload;
const slaveIds = (p.slaveIds || []).map(Number).filter(n => n >= 1 && n <= 200);

if (slaveIds.length === 0) {
    msg.payload = { action: 'report-result', error: 'No slave IDs selected.' };
    return [null, msg];
}
if (!p.dateFrom || !p.dateTo) {
    msg.payload = { action: 'report-result', error: 'Both From and To dates are required.' };
    return [null, msg];
}

const duration = parseInt(p.duration) || 5;
const dateStart = p.dateFrom + ' 00:00:00';
const dateEnd   = p.dateTo   + ' 23:59:59';

// Fetch raw rows – bucketing is done in Format Report Result using the
// actual first-log timestamp, not midnight-aligned buckets.
msg.topic = `
SELECT
    slave_id,
    CONVERT(varchar(19), logged_at, 120) AS logged_at,
    dp_value,
    alarm_status
FROM dp_log
WHERE slave_id IN (${slaveIds.join(',')})
  AND logged_at BETWEEN '${dateStart}' AND '${dateEnd}'
  AND alarm_status = 'NORMAL'
ORDER BY slave_id, logged_at
`;

msg.payload = {};
msg._reportMeta = { slaveIds, duration, dateFrom: p.dateFrom, dateTo: p.dateTo };

return [msg, null];

if (msg.error || msg.payload === undefined || msg.payload === null) {
    node.warn(`Modbus error or empty response for slave ${msg.slaveId || '?'}`);
    return [null, msg];
}

if (Buffer.isBuffer(msg.payload)) {
    msg.payload = Array.from(msg.payload);
}

if (!Array.isArray(msg.payload)) {
    if (msg.payload && Array.isArray(msg.payload.data)) {
        msg.payload = msg.payload.data;
    } else {
        msg.payload = [];
    }
}

return [msg, null];

if (!msg.payload) return null;

// LOGOUT — revoke token stored by the frontend
if (msg.payload.action === 'logout') {
    const token = msg.payload.sessionToken || null;
    if (token) {
        let authSockets = flow.get('authenticatedSockets', 'file') || {};
        delete authSockets[token];
        flow.set('authenticatedSockets', authSockets);
        flow.set('authenticatedSockets', authSockets, 'file');
    }
    return null;
}

if (msg.payload.action !== 'login-check') return null;

const USERS = {
    'Admin': { password: '1234', role: 'admin'  },
    'user':    { password: 'user',    role: 'viewer' }
};

const userId   = (msg.payload.userId   || '').trim();
const password = (msg.payload.password || '').trim();
const socketId = msg._client ? msg._client.socketId : 'unknown';
const now      = Date.now();

const lockKey   = 'loginLock_'  + socketId;
const failKey   = 'loginFails_' + socketId;
const lockUntil = flow.get(lockKey) || 0;

if (now < lockUntil) {
    const secsLeft = Math.ceil((lockUntil - now) / 1000);
    msg.payload = { action: 'login-result', success: false, locked: true, secsLeft };
    return [null, msg];
}

const fails = flow.get(failKey) || 0;

const userRecord = USERS[userId];
if (userRecord && userRecord.password === password) {
    const userRole = userRecord.role;
    flow.set(failKey, 0);
    flow.set(lockKey, 0);

    // Generate a persistent session token (survives WS reconnects & server restarts)
    const token = 'jp_' + now.toString(36) + '_' + Math.random().toString(36).slice(2, 10);
    let authSockets = flow.get('authenticatedSockets', 'file') || {};

    // Prune oldest entries if map grows too large (keep max 30)
    const keys = Object.keys(authSockets);
    if (keys.length > 50) {
        keys.sort((a, b) => (authSockets[a].ts || 0) - (authSockets[b].ts || 0));
        keys.slice(0, keys.length - 30).forEach(k => delete authSockets[k]);
    }
    authSockets[token] = { ts: now, userId, role: userRole };
    flow.set('authenticatedSockets', authSockets, 'file');

    const client = msg._client;

    // Out[0] → Navigate to DP (ui-control): performs SPA page navigation (no full reload)
    const navMsg = { payload: { page: 'Temp' }, _client: client };

    // Out[1] → Login Page: delivers token so the frontend can persist it in localStorage.
    //          The Login Page MUST NOT call window.location.href — the ui-control already navigated.
    const resultMsg = Object.assign({}, msg);
    resultMsg.payload = { action: 'login-result', success: true, sessionToken: token, userId, role: userRole };
    resultMsg._client = client;

    const loginEvMsg = { payload: { event_type: 'login', event_desc: 'User ' + userId + ' logged in', user_id: userId } };
    return [navMsg, resultMsg, loginEvMsg];

} else {
    const newFails = fails + 1;
    flow.set(failKey, newFails);
    if (newFails >= 3) {
        flow.set(lockKey, now + 60000);
        flow.set(failKey, 0);
        msg.payload = { action: 'login-result', success: false, locked: true, secsLeft: 60 };
    } else {
        msg.payload = { action: 'login-result', success: false, locked: false, attemptsLeft: 3 - newFails };
    }
    return [null, msg];
}

// Receives from Update Row — ONLINE.
// msg._logEntry = { slaveId, tempValue, alarm, ts }
if (!msg._logEntry) return null;

const e = msg._logEntry;
const tv = Number(e.tempValue);
if (isNaN(tv)) { node.warn('[LivePusher] tempValue is NaN for slave ' + e.slaveId); return null; }

const slaveId = Number(e.slaveId);

// Build a second-level timestamp key: "slaveId_YYYY-MM-DD HH:MM:SS"
const d = new Date(typeof e.ts === 'number' ? e.ts : Number(e.ts));
const pad = n => String(n).padStart(2, '0');
const secKey = slaveId + '_' +
    d.getFullYear() + '-' +
    pad(d.getMonth() + 1) + '-' +
    pad(d.getDate()) + ' ' +
    pad(d.getHours()) + ':' +
    pad(d.getMinutes()) + ':' +
    pad(d.getSeconds());

// Retrieve accumulator stored per slave
let buckets = context.get('secBuckets') || {};

// If the key changed (new second), emit the average for the old second first
let outMsg = null;
const existing = buckets[slaveId];

if (existing && existing.key !== secKey) {
    // Compute average of accumulated values
    const avg = existing.sum / existing.count;
    // Determine alarm: if any reading in this second was ALERT, mark ALERT
    const alarm = existing.hasAlert ? 'ALERT' : 'NORMAL';
    outMsg = {
        payload: {
            action: 'chart-live-point',
            slaveId: slaveId,
            tempValue: avg,
            alarm: alarm,
            ts: existing.ts
        }
    };
    // Start fresh bucket for new second
    buckets[slaveId] = { key: secKey, sum: tv, count: 1, hasAlert: e.alarm === 'ALERT', ts: e.ts };
} else if (!existing) {
    // First reading for this slave
    buckets[slaveId] = { key: secKey, sum: tv, count: 1, hasAlert: e.alarm === 'ALERT', ts: e.ts };
} else {
    // Same second — accumulate
    buckets[slaveId].sum += tv;
    buckets[slaveId].count += 1;
    if (e.alarm === 'ALERT') buckets[slaveId].hasAlert = true;
}

context.set('secBuckets', buckets);

return outMsg;

if (!msg.payload || !msg.payload.action) return null;

// chart-query → Build Chart Query
if (msg.payload.action === 'chart-query') return [msg, null];

// session-check / do-logout → Session Check + Logout node
if (msg.payload.action === 'session-check' || msg.payload.action === 'do-logout' || msg.payload.action === 'session-keepalive') return [null, msg];

return null;

if (!msg.payload || msg.payload.action !== 'chart-query') return null;

const p = msg.payload;
const slaveId = Number(p.slaveId);

if (isNaN(slaveId) || slaveId < 1 || slaveId > 200) {
    msg.payload = { action: 'chart-history-result', error: 'Invalid Slave ID (must be 1–200).' };
    return [null, msg];
}
if (!p.dateFrom || !p.dateTo) {
    msg.payload = { action: 'chart-history-result', error: 'Both From and To dates are required.' };
    return [null, msg];
}

const dateStart = p.dateFrom + ' 00:00:00';
const dateEnd   = p.dateTo   + ' 23:59:59';
const duration = parseInt(p.duration) || 5;

let periodExpr, groupBy;

if (duration === 60) {
    periodExpr = "CONVERT(varchar(13), logged_at, 120) + ':00:00'";
    groupBy    = "CONVERT(varchar(13), logged_at, 120)";
} else if (duration === 1) {
    periodExpr = "CONVERT(varchar(16), logged_at, 120) + ':00'";
    groupBy    = "CONVERT(varchar(16), logged_at, 120)";
} else {
    periodExpr = `CONVERT(varchar(16), DATEADD(minute, (DATEDIFF(minute, 0, logged_at) / ${duration}) * ${duration}, 0), 120)`;
    groupBy    = `DATEADD(minute, (DATEDIFF(minute, 0, logged_at) / ${duration}) * ${duration}, 0)`;
}

msg.topic = `
SELECT
    ${periodExpr} AS period,
    ROUND(AVG(CAST(dp_value AS FLOAT)/10), 2) AS dp_value,
    MAX(CASE WHEN alarm_status = 'ALERT' THEN 1 ELSE 0 END) AS had_alert
FROM dp_log
WHERE slave_id = ${slaveId}
  AND logged_at BETWEEN '${dateStart}' AND '${dateEnd}'
GROUP BY ${groupBy}
ORDER BY period
`;

msg.payload = {};
msg._chartMeta = { slaveId, duration, dateFrom: p.dateFrom, dateTo: p.dateTo };

return [msg, null];

const rows = msg.payload || [];
const meta  = msg._chartMeta || {};

msg.payload = {
    action: 'chart-history-result',
    rows: rows.map(r => ({
        period:    r.period,
        dp_value:  parseFloat(r.dp_value),
        had_alert: r.had_alert === 1 || r.had_alert === true
    })),
    meta:  meta,
    count: rows.length
};

return msg;

const _cfgPath = global.get('CONFIG_PATH');
function _readCfg() {
  try { return JSON.parse(_fs.readFileSync(_cfgPath, 'utf8')); }
  catch(e) { return { slaveIds: [], activeSlaveIds: [], deviceSettings: {} }; }
}
function _saveCfg(c) {
  try { _fs.writeFileSync(_cfgPath, JSON.stringify(c, null, 2), 'utf8'); }
  catch(e) { node.warn('cfg write error: ' + e.message); }
}
let slaveId = (msg.modbusRequest && msg.modbusRequest.unitid) ||
              (msg.payload && msg.payload.unitid) ||
              msg.slaveId || null;

if (!slaveId) { node.warn('ONLINE: slaveId not found'); return null; }

let currentTime = Date.now();
flow.set(`lastResponseTime_${slaveId}`, currentTime);
flow.set(`isOffline_${slaveId}`, false);

let rawData = Array.isArray(msg.payload) ? msg.payload :
              (msg.payload && msg.payload.data ? Array.from(msg.payload.data) : []);

function toSigned16(val) { return val > 32767 ? val - 65536 : val; }

const cfg = _readCfg();
const device = (cfg.deviceSettings || {})['slave_' + slaveId] || { Destination: '', LSP: 0, HSP: 70 };

let rawTemp = toSigned16(rawData[0] ?? 0);
let tempValue = rawTemp / 10;
let alarm = (tempValue < device.LSP || tempValue > device.HSP) ? 'ALERT' : 'NORMAL';

let row = {
    ID: slaveId,
    Destination: device.Destination || '',
    TempValue: tempValue.toFixed(1),
    LSP: device.LSP,
    HSP: device.HSP,
    notifyEmail: device.notifyEmail || '',
    Alarm: alarm,
    Status: 'ONLINE',
    lastSeen: currentTime
};

let tableData = flow.get('tableData', 'file') || {};
const wasOffline = (tableData['slave_' + slaveId]?.Status === 'OFFLINE');
tableData['slave_' + slaveId] = row;
flow.set('tableData', tableData, 'file');

if (wasOffline) node.warn(`[Back Online] Slave ${slaveId}`);

// Add to activeSlaveIds in config only if in slaveIds and not already active
const explicitIds = (cfg.slaveIds || []).map(Number);
if (explicitIds.includes(Number(slaveId))) {
    const activeIds = (cfg.activeSlaveIds || []).map(Number);
    if (!activeIds.includes(Number(slaveId))) {
        cfg.activeSlaveIds = [...activeIds, Number(slaveId)].sort((a, b) => a - b);
        _saveCfg(cfg);
    }
}

// ── Periodic offline check (every 5 seconds) ──────────────────────────────────
// Detects devices that stopped responding even if Modbus doesn't raise an error
const lastOfflineCheck = flow.get('lastOfflineCheck') || 0;
if (currentTime - lastOfflineCheck > 5000) {
    flow.set('lastOfflineCheck', currentTime);
    const allActive = (cfg.activeSlaveIds || []).map(Number);
    let cfgDirty = false;

    allActive.forEach(id => {
        if (Number(id) === Number(slaveId)) return; // this device just responded — skip
        const lastSeen = flow.get(`lastResponseTime_${id}`) || 0;
        const alreadyOffline = flow.get(`isOffline_${id}`) || false;
        if (!alreadyOffline && lastSeen > 0 && (currentTime - lastSeen) > 5000) {
            flow.set(`isOffline_${id}`, true);
            const offDev = (cfg.deviceSettings || {})['slave_' + id] || { Destination: '', LSP: 0, HSP: 70 };
            tableData['slave_' + id] = {
                ID: id,
                Destination: offDev.Destination || '',
                TempValue: '-',
                LSP: offDev.LSP,
                HSP: offDev.HSP,
                Alarm: 'OFFLINE',
                Status: 'OFFLINE',
                lastSeen: tableData['slave_' + id]?.lastSeen || 0
            };
            cfg.activeSlaveIds = (cfg.activeSlaveIds || []).filter(x => Number(x) !== id);
            cfgDirty = true;
            node.warn(`[Auto-OFFLINE] Slave ${id} — no response for ${Math.round((currentTime - lastSeen)/1000)}s`);
        }
    });

    if (cfgDirty) {
        flow.set('tableData', tableData, 'file');
        _saveCfg(cfg);
    }
}
// ─────────────────────────────────────────────────────────────────────────────

const SLAVE_IDS = cfg.slaveIds || [];
msg._logEntry = { slaveId, tempValue, alarm, ts: currentTime };

const lastUIUpdate = flow.get('lastUIUpdate') || 0;
let uiMsg = null;
if (currentTime - lastUIUpdate >= 1000) {
    flow.set('lastUIUpdate', currentTime);
    uiMsg = { ...msg };
    uiMsg.payload = SLAVE_IDS.map(id => tableData['slave_' + id] || {
        ID: id, Destination: '', TempValue: '-',
        LSP: 0, HSP: 70, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0
    });
}

return [msg, uiMsg];

if (!msg.payload) return null;

function readSockets() {
    let s = flow.get('authenticatedSockets') || {};
    if (Object.keys(s).length === 0) {
        try { s = flow.get('authenticatedSockets', 'file') || {}; } catch (e) { }
        if (Object.keys(s).length > 0) flow.set('authenticatedSockets', s);
    }
    return s;
}

function writeSockets(s) {
    flow.set('authenticatedSockets', s);
    try { flow.set('authenticatedSockets', s, 'file'); } catch (e) { }
}

// ── Silent keepalive ──────────────────────────────────────
if (msg.payload.action === 'session-keepalive') {
    const token = msg.payload.sessionToken || null;
    let valid = false;
    if (token) {
        let s = readSockets();
        if (s[token]) {
            s[token].ts = Date.now();
            writeSockets(s);
            valid = true;
        }
    }
    return {
        payload: { action: 'keepalive-ack', success: valid, ts: Date.now() }
    };
}

// ── Logout ────────────────────────────────────────────────
if (msg.payload.action === 'do-logout') {
    const token = msg.payload.sessionToken || null;
    if (token) {
        let s = readSockets();
        delete s[token];
        writeSockets(s);
    }
    const logoutEvMsg = { payload: { event_type: 'logout', event_desc: 'User logged out', user_id: msg.payload.userId || 'User' } };
    msg.payload = { action: 'session-result', authenticated: false };
    return [msg, logoutEvMsg];
}

if (msg.payload.action !== 'session-check') return null;

// ── Session check ─────────────────────────────────────────
const token = msg.payload.sessionToken || null;
let authSockets = readSockets();
const session = token ? authSockets[token] : null;

if (!session) {
    if (token) {
        // Token was provided but not found — deleted by logout
        msg.payload = { action: 'session-result', authenticated: false };
        return msg;
    }
    // No token — fresh browser, allow through as authenticated
    const lastUser = Object.values(authSockets).slice(-1)[0] || {};
    msg.payload = {
        action: 'session-result',
        authenticated: true,
        userId: lastUser.userId || 'Admin',
        role: lastUser.role || 'admin'
    };
    return msg;
}

// Refresh timestamp
session.ts = Date.now();
authSockets[token] = session;
writeSockets(authSockets);

msg.payload = {
    action: 'session-result',
    authenticated: true,
    userId: session.userId || 'admin',
    role: session.role || 'viewer'
};
return msg;

