if (!msg.payload || !msg.payload.action) return null;

if (msg.payload.action === 'device-settings-save') {
    let d = msg.payload;
    const slaveKey = 'slave_' + d.id;
    const _fs2 = _fs, _path2 = _path;
    const _cfgPath2 = global.get('CONFIG_PATH');
    let _cfg2; try { _cfg2 = JSON.parse(_fs2.readFileSync(_cfgPath2, 'utf8')); } catch(e) { _cfg2 = { slaveIds: [], activeSlaveIds: [], deviceSettings: {} }; }
    if (!_cfg2.deviceSettings) _cfg2.deviceSettings = {};
    const oldSettings = _cfg2.deviceSettings[slaveKey] || {};
