        LSP: 0, HSP: 0, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0
    };
    row.Destination = d.destination || '';
    row.LSP = parseFloat(d.lsp) || 0;
    row.HSP = parseFloat(d.hsp) || 0;
    row.notifyEmail = newEmail;
    tableData[slaveKey] = row;
    flow.set('tableData', tableData, 'file');
    const devLabel = 'Device ' + (d.id||'?') + (d.destination ? ' (' + d.destination + ')' : '');
    const settingsEvMsg = { payload: { event_type: 'settings-changed', event_desc: devLabel + ' settings updated — Destination: ' + (d.destination||'-') + ', LSP: ' + (d.lsp||0) + ', HSP: ' + (d.hsp||0), user_id: 'Admin' } };
    let emailEvMsg = null;
    if (!oldEmail && newEmail) {
        emailEvMsg = { payload: { event_type: 'settings-changed', event_desc: 'Notify email added for ' + devLabel + ': ' + newEmail, user_id: 'Admin' } };
    } else if (oldEmail && !newEmail) {
        emailEvMsg = { payload: { event_type: 'settings-changed', event_desc: 'Notify email removed for ' + devLabel, user_id: 'Admin' } };
    } else if (oldEmail && newEmail && oldEmail !== newEmail) {
        emailEvMsg = { payload: { event_type: 'settings-changed', event_desc: 'Notify email changed for ' + devLabel + ': ' + newEmail, user_id: 'Admin' } };
    }
    msg.payload = { action: 'device-settings-row-update', row: row };
    const evtOutput = emailEvMsg ? [settingsEvMsg, emailEvMsg] : settingsEvMsg;
    return [msg, null, null, null, null, null, null, evtOutput];
}

if (msg.payload.action === 'load-contacts') {
    let contacts = [];
    try {
        const csv = _fs.readFileSync(global.get('CONTACTS_PATH'), 'utf8');
        contacts = csv.split('\n')
            .map(l => l.trim()).filter(l => l && !l.startsWith('#'))
            .map(l => { const p = l.split(','); return { name: (p[0]||'').trim(), email: (p[1]||'').trim() }; })
            .filter(c => c.email && c.email.toLowerCase() !== 'email');
    } catch(e) { contacts = []; }
    msg.payload = { action: 'contacts-result', contacts };
    return [msg, null, null, null, null, null, null, null];
}

if (msg.payload.action === 'event-log-query') return [null, null, null, msg, null, null, null, null];
if (msg.payload.action === 'set-active-ids')  return [msg, null, null, null, null, null, null, null];
if (msg.payload.action === 'save-email-config') {
    const incomingPwd = msg.payload.password || '';
    let dc; try { dc = JSON.parse(_fs.readFileSync(global.get('CONFIG_PATH'), 'utf8')); } catch(e) { dc = {}; }
    const storedPwd = dc.emailSettingsPassword || '';
    if (storedPwd && incomingPwd !== storedPwd) {
        msg.payload = { action: 'email-config-result', error: 'Incorrect password.' };
        return [msg, null, null, null, null, null, null, null];
    }
    const cfg = { fromEmail: (msg.payload.config || {}).fromEmail || '' };
    flow.set('emailConfig', cfg, 'file');
    dc.emailSettingsPassword = incomingPwd;
    try { _fs.writeFileSync(global.get('CONFIG_PATH'), JSON.stringify(dc, null, 2), 'utf8'); } catch(e) { node.warn('cfg write error: ' + e.message); }
    msg.payload = { action: 'email-config-result', config: cfg, hasPassword: !!(incomingPwd) };
    return [msg, null, null, null, null, null, null, null];
}

if (msg.payload.action === 'load-email-config') {
    const cfg = flow.get('emailConfig', 'file') || { fromEmail: '' };
    let _dc; try { _dc = JSON.parse(_fs.readFileSync(global.get('CONFIG_PATH'), 'utf8')); } catch(e) { _dc = {}; }
    const hasPassword = !!(_dc.emailSettingsPassword);
    msg.payload = { action: 'email-config-result', config: { fromEmail: cfg.fromEmail || '' }, hasPassword, loadOnly: true };
    return [msg, null, null, null, null, null, null, null];
}

if (msg.payload.action === 'change-email-password') {
    const oldPwd = msg.payload.oldPassword || '';
    const newPwd = msg.payload.newPassword || '';
    let dc; try { dc = JSON.parse(_fs.readFileSync(global.get('CONFIG_PATH'), 'utf8')); } catch(e) { dc = {}; }
    const storedPwd = dc.emailSettingsPassword || '';
    if (storedPwd && oldPwd !== storedPwd) {
        msg.payload = { action: 'change-password-result', success: false, error: 'Incorrect old password.' };
        return [msg, null, null, null, null, null, null, null];
    }
    dc.emailSettingsPassword = newPwd;
    try { _fs.writeFileSync(global.get('CONFIG_PATH'), JSON.stringify(dc, null, 2), 'utf8'); } catch(e) { node.warn('cfg write error: ' + e.message); }
    msg.payload = { action: 'change-password-result', success: true };
    return [msg, null, null, null, null, null, null, null];
}

if (msg.payload.action === 'auth-check')      return [null, msg, null, null, null, null, null, null];
if (msg.payload.action === 'report-query')    return [null, null, msg, null, null, null, null, null];
if (msg.payload.action === 'session-check' || msg.payload.action === 'do-logout')   return [null, null, null, null, msg, null, null, null];
if (msg.payload.action === 'alarm-report-query') return [null, null, null, null, null, msg, null, null];
if (msg.payload.action === 'ack-save')           return [null, null, null, null, null, null, msg, null];
if (msg.payload.action === 'session-keepalive')  return [null, null, null, null, msg, null, null, null];
if (msg.payload.action === 'get-slave-ids' || msg.payload.action === 'save-slave-ids')

return [null, null, null, null, msg, null, null, null];

const rows     = msg.payload || [];
const meta     = msg._reportMeta || {};
const _fs3 = _fs, _path3 = _path;
const _cfgPath3 = global.get('CONFIG_PATH');
let _cfg3; try { _cfg3 = JSON.parse(_fs3.readFileSync(_cfgPath3, 'utf8')); } catch(e) { _cfg3 = { deviceSettings: {} }; }
const settings = _cfg3.deviceSettings || {};
const duration = parseInt(meta.duration) || 5;
const durationMs = duration * 60 * 1000;

// Group raw rows by slave_id (already ordered by logged_at from SQL)
const bySlave = {};
rows.forEach(r => {
    const sid = String(r.slave_id);
    if (!bySlave[sid]) bySlave[sid] = [];
    bySlave[sid].push(r);
});

const pad = n => String(n).padStart(2, '0');

function tsToStr(d) {
    return d.getFullYear() + '-' + pad(d.getMonth()+1) + '-' + pad(d.getDate()) +
           ' ' + pad(d.getHours()) + ':' + pad(d.getMinutes()) + ':' + pad(d.getSeconds());
}

const result = [];

Object.keys(bySlave).forEach(sid => {
    const slaveRows = bySlave[sid];
    if (!slaveRows.length) return;

    const d = settings['slave_' + sid] || { Destination: '' };

    // Anchor: the very first actual log timestamp for this slave
    const firstTs  = new Date(slaveRows[0].logged_at.replace(' ', 'T'));
    const lastTs   = new Date(slaveRows[slaveRows.length - 1].logged_at.replace(' ', 'T'));

    let bucketStart = new Date(firstTs.getTime());
    let rowIdx = 0; // walk forward instead of filtering for efficiency

    while (bucketStart <= lastTs) {
        const bucketEnd = new Date(bucketStart.getTime() + durationMs);

        // Collect rows in [bucketStart, bucketEnd)
        const inBucket = [];
        while (rowIdx < slaveRows.length) {
            const t = new Date(slaveRows[rowIdx].logged_at.replace(' ', 'T'));
            if (t >= bucketEnd) break;
            if (t >= bucketStart) inBucket.push(slaveRows[rowIdx]);
            rowIdx++;
        }

        if (inBucket.length > 0) {
            const sum = inBucket.reduce((s, r) => s + parseFloat(r.dp_value || 0), 0);
            const avgVal  = sum / inBucket.length;
            const hadAlert = inBucket.some(r => r.alarm_status === 'ALERT') ? 1 : 0;

            result.push({
                slave_id:      parseInt(sid),
                period:        tsToStr(bucketStart),   // label = bucket start (first-log anchor)
                dp_value:      Math.round(avgVal * 10) / 10,
                reading_count: inBucket.length,
                had_alert:     hadAlert,
                location:      d.Destination || '',
                roomNo:        d.Destination || ''
            });
        }

        bucketStart = bucketEnd;
    }
});

// Sort by slave_id then period
result.sort((a, b) => a.slave_id - b.slave_id || a.period.localeCompare(b.period));

msg.payload = {
    action: 'report-result',
    rows:   result,
    meta,
    count:  result.length
};
return msg;

if (!msg.payload || msg.payload.action !== 'alarm-report-query') return null;

const p = msg.payload;
const slaveIds = (p.slaveIds || []).map(Number).filter(n => n >= 1 && n <= 200);

if (slaveIds.length === 0) {
    msg.payload = { action: 'alarm-report-result', error: 'No slave IDs selected.' };
    return [null, msg];
}
if (!p.dateFrom || !p.dateTo) {
    msg.payload = { action: 'alarm-report-result', error: 'Both date fields are required.' };
    return [null, msg];
}

const dateStart = p.dateFrom + ' ' + (p.hourFrom || '00') + ':00:00';
const dateEnd   = p.dateTo   + ' ' + (p.hourTo   || '23') + ':59:59';

let periodExpr, groupBy;
if (p.interval === 'hourly') {
    periodExpr = "CONVERT(varchar(13), logged_at, 120) + ':00:00'";
    groupBy    = "slave_id, CONVERT(varchar(13), logged_at, 120)";
} else if (p.interval === 'minutely') {
    periodExpr = "CONVERT(varchar(16), logged_at, 120) + ':00'";
    groupBy    = "slave_id, CONVERT(varchar(16), logged_at, 120)";
} else {
    periodExpr = "CONVERT(varchar(10), logged_at, 120)";
    groupBy    = "slave_id, CONVERT(varchar(10), logged_at, 120)";
}

msg.topic = `
SELECT
    slave_id,
    ${periodExpr} AS period,
    MIN(CASE WHEN alarm_status='ALERT' THEN dp_value END) AS min_alert_dp,
    MAX(CASE WHEN alarm_status='ALERT' THEN dp_value END) AS max_alert_dp,
    MIN(CASE WHEN alarm_status='ALERT' THEN logged_at END) AS alarm_start,
    MAX(CASE WHEN alarm_status='ALERT' THEN logged_at END) AS alarm_end,
    COUNT(CASE WHEN alarm_status='ALERT' THEN 1 END) AS alert_count
FROM dp_log
WHERE slave_id IN (${slaveIds.join(',')})
  AND logged_at BETWEEN '${dateStart}' AND '${dateEnd}'
GROUP BY ${groupBy}
HAVING COUNT(CASE WHEN alarm_status='ALERT' THEN 1 END) > 0
ORDER BY slave_id, period
`;

msg.payload = {};
msg._alarmMeta = { slaveIds, interval: p.interval, dateFrom: p.dateFrom, dateTo: p.dateTo };
return [msg, null];

const rows = msg.payload || [];
const meta = msg._alarmMeta || {};
const settings = flow.get('deviceSettings', 'file') || {};
const acks = flow.get('alarmAcks', 'file') || {};

const enriched = rows.map(r => {
    const d = settings['slave_' + r.slave_id] || { Destination: '', LSP: -60, HSP: 60 };
    const lsp = d.LSP != null ? d.LSP : -60;
    const hsp = d.HSP != null ? d.HSP : 60;
    const minDp = Number(r.min_alert_dp);
    const maxDp = Number(r.max_alert_dp);
    let alarmType = 'HIGH';
    if (minDp < lsp && maxDp <= hsp) alarmType = 'LOW';
    else if (maxDp > hsp && minDp < lsp) alarmType = 'HIGH';
    const alertDp = alarmType === 'LOW' ? minDp : maxDp;
    const ackKey = r.slave_id + '_' + r.period;
    return {
        slave_id:     Number(r.slave_id),
        period:       r.period,
        min_alert_dp: minDp,
        max_alert_dp: maxDp,
        alert_dp_value: alertDp,
        alarm_start:  r.alarm_start,
        alarm_end:    r.alarm_end,
        alert_count:  Number(r.alert_count),
        location:     d.Destination || '',
        roomNo:       d.Destination || '',
        lsp, hsp, alarmType,
        ack: acks[ackKey] || null
    };
});

msg.payload = { action: 'alarm-report-result', rows: enriched, meta, count: enriched.length };
return msg;

if (!msg.payload || msg.payload.action !== 'ack-save') return null;

const d = msg.payload;
const acks = flow.get('alarmAcks', 'file') || {};
const key = d.slaveId + '_' + d.period;

acks[key] = {
    slaveId:     d.slaveId,
    period:      d.period,
    destination: d.destination || '',
    alarmStart:  d.alarmStart,
    alarmEnd:    d.alarmEnd,
    ackedBy:     d.ackedBy || 'Unknown',
    ackedAt:     new Date().toISOString(),
    remarks:     d.remarks || ''
};
flow.set('alarmAcks', acks, 'file');

// Log alarm acknowledgement event
  try { node.send([null, { payload: { event_type: 'alarm-acked', event_desc: 'Alarm acknowledged for Device ' + (d.slaveId||'?') + ' (Period: ' + (d.period||'?') + ')', user_id: d.ackedBy || 'Admin' } }]); } catch(e) {}
  msg.payload = { action: 'ack-result', success: true, key, ack: acks[key] };
return msg;

const tableData = flow.get('tableData', 'file') || {};
const rows = Object.values(tableData);

const now = Date.now();
const activeAlerts = rows
    .filter(r => r && r.Status === 'ONLINE' && r.Alarm === 'ALERT')
    .map(r => ({
        slaveId: r.ID,
        destination: r.Destination || '',
        alarmValue: r.TempValue != null ? r.TempValue : '—',
        lsp: r.LSP,
        hsp: r.HSP,
        alarmType: (r.TempValue !== undefined && r.TempValue !== null && r.LSP !== undefined)
            ? (parseFloat(r.TempValue) < r.LSP ? 'LOW' : 'HIGH')
            : 'HIGH',
        notifyEmail: r.notifyEmail || '',
        alarmTime: now,
        alarmTimeStr: (() => {
            const d = new Date(now);
            const pad = n => String(n).padStart(2, '0');
            return `${pad(d.getDate())}-${pad(d.getMonth() + 1)}-${d.getFullYear()} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
        })()
    }));

const prevAlerts = flow.get('activeAlerts') || [];
flow.set('activeAlerts', activeAlerts);

const prevIds = new Set(prevAlerts.map(a => a.slaveId));
const newAlerts = activeAlerts.filter(a => !prevIds.has(a.slaveId));

if (newAlerts.length > 0) {
    const pendingEmails = flow.get('pendingEmailAlerts') || [];
    newAlerts.forEach(a => pendingEmails.push(a));
    flow.set('pendingEmailAlerts', pendingEmails);
}

return {
    payload: {
        action: 'alert-update',
        alerts: activeAlerts,
        newAlerts: newAlerts,
        totalCount: activeAlerts.length
    },
    _newAlerts: newAlerts
};

// SQL Keepalive Query Builder
msg.topic = "SELECT 1 as connection_test, GETDATE() as [current_time]";
msg.payload = {};
return msg;

// Handles save/load of email configuration
if (!msg.payload || !msg.payload.action) return null;

if (msg.payload.action === 'save-email-config') {
    const incomingPwd = msg.payload.password || '';
    const _fs2 = require('fs');
    let dc; try { dc = JSON.parse(_fs2.readFileSync(global.get('CONFIG_PATH'), 'utf8')); } catch(e) { dc = {}; }
    const storedPwd = dc.emailSettingsPassword || '';
    if (storedPwd && incomingPwd !== storedPwd) {
        msg.payload = { action: 'email-config-result', error: 'Incorrect password.' };
        return msg;
    }
    const cfg = { fromEmail: (msg.payload.config || {}).fromEmail || '' };
    flow.set('emailConfig', cfg, 'file');
    dc.emailSettingsPassword = incomingPwd;
    try { _fs2.writeFileSync(global.get('CONFIG_PATH'), JSON.stringify(dc, null, 2), 'utf8'); } catch(e) { node.warn('cfg write error: ' + e.message); }
    msg.payload = { action: 'email-config-result', config: cfg };
    return msg;
}

if (msg.payload.action === 'load-email-config') {
    const cfg = flow.get('emailConfig', 'file') || { fromEmail: '' };
    let _dc2; try { _dc2 = JSON.parse(_fs2.readFileSync(global.get('CONFIG_PATH'), 'utf8')); } catch(e) { _dc2 = {}; }
    const hasPassword2 = !!(_dc2.emailSettingsPassword);
    msg.payload = { action: 'email-config-result', config: { fromEmail: cfg.fromEmail || '' }, hasPassword: hasPassword2 };
    return msg;
}

return null;

// Email Dispatcher — per-device notifyEmail, HIGH+LOW alerts, 3-min cooldown per device
const newAlerts = msg._newAlerts || [];
if (newAlerts.length === 0) return null;

const emailCfg = flow.get('emailConfig', 'file') || {};
const fromEmail = emailCfg.fromEmail || '';

const COOLDOWN_MS = 3 * 60 * 1000;
const now = Date.now();
const outMessages = [];

for (const alert of newAlerts) {
    const toEmail = alert.notifyEmail || '';
    if (!toEmail) continue;

    const cooldownKey = 'emailCooldown_' + alert.slaveId;
    const lastSent = flow.get(cooldownKey) || 0;
    if ((now - lastSent) < COOLDOWN_MS) continue;

    const alarmLabel = alert.alarmType === 'LOW'
        ? 'LOW ALERT — Temperature below Low Set Point'
        : 'HIGH ALERT — Temperature above High Set Point';

    const subject = `[ALERT] Slave ${alert.slaveId}${alert.destination ? ' — ' + alert.destination : ''} | Jetpace EMS`;
    const body =
        `TEMPERATURE ALERT — Jetpace EMS\n\n` +
        `Device     : Slave ID ${alert.slaveId}${alert.destination ? ' (' + alert.destination + ')' : ''}\n` +
        `Alert Type : ${alarmLabel}\n` +
        `Temperature: ${alert.alarmValue} °C\n` +
        `LSP        : ${alert.lsp} °C\n` +
        `HSP        : ${alert.hsp} °C\n` +
        `Time       : ${alert.alarmTimeStr}\n\n` +
        `Please take immediate action.\n\n` +
        `— Jetpace EMS`;

    const emailMsg = { topic: subject, payload: body, to: toEmail };
    if (fromEmail) emailMsg.from = fromEmail;
    outMessages.push(emailMsg);
    flow.set(cooldownKey, now);
}

if (outMessages.length === 0) return null;
return [outMessages];

// Triggered when UI sends action: 'save-slave-ids'
if (!msg.payload || msg.payload.action !== 'save-slave-ids') return null;

const ids = msg.payload.slaveIds || [];
flow.set('persistedSlaveIds', ids, 'file');

msg.payload = {
    action: 'slave-ids-restored',
    slaveIds: ids
};
return msg;

const _cfgPath = global.get('CONFIG_PATH');
function _readCfg() {
  try { return JSON.parse(_fs.readFileSync(_cfgPath, 'utf8')); }
  catch(e) { return { slaveIds: [], activeSlaveIds: [], deviceSettings: {} }; }
}
function _saveCfg(c) {
  try { _fs.writeFileSync(_cfgPath, JSON.stringify(c, null, 2), 'utf8'); }
  catch(e) { node.warn('cfg write error: ' + e.message); }
}
flow.set('rrIndex', 0);
flow.set('bgScanQueue', []);
const cfg = _readCfg();
node.warn('Boot: slaveIds=' + (cfg.slaveIds||[]).join(',') + ' activeIds=' + (cfg.activeSlaveIds||[]).join(','));
return null;

// Startup trigger: payload = {}
if (msg.payload && typeof msg.payload === 'object' && Object.keys(msg.payload).length === 0) {
    msg.payload = { event_type: 'system-start', event_desc: 'Jetpace EMS started', user_id: 'System' };
}
if (!msg.payload || !msg.payload.event_type) return null;
const now = new Date();
const pad = n => String(n).padStart(2,'0');
const ts = now.getFullYear()+'-'+pad(now.getMonth()+1)+'-'+pad(now.getDate())+' '+pad(now.getHours())+':'+pad(now.getMinutes())+':'+pad(now.getSeconds());
const esc = s => String(s||'').replace(/'/g,"''").substring(0,490);
msg.topic = "INSERT INTO event_log (event_type,event_desc,user_id,occurred_at) VALUES ('"+esc(msg.payload.event_type)+"','"+esc(msg.payload.event_desc)+"','"+esc(msg.payload.user_id||'System')+"','"+ts+"')";
msg.payload = {};
return msg;

if (!msg.payload || msg.payload.action !== 'event-log-query') return null;
const p = msg.payload;
const today = new Date().toISOString().split('T')[0];
const esc = s => String(s||'').replace(/'/g,"''");
const dateFrom = (p.dateFrom || today) + ' 00:00:00';
const dateTo   = (p.dateTo   || today) + ' 23:59:59';
let where = "occurred_at BETWEEN '"+dateFrom+"' AND '"+dateTo+"'";
if (p.eventType && p.eventType !== 'all') where += " AND event_type = '"+esc(p.eventType)+"'";
if (p.userId && p.userId.trim()) where += " AND user_id LIKE '%"+esc(p.userId.trim())+"%'";
msg.topic = "SELECT TOP 500 id, event_type, event_desc, ISNULL(user_id,'System') AS user_id, CONVERT(varchar(19), occurred_at, 120) AS occurred_at FROM event_log WHERE "+where+" ORDER BY occurred_at DESC";
msg.payload = {};
return msg;

const rows = msg.payload || [];
msg.payload = {
  action: 'event-log-result',
  rows: rows.map(r => ({
    id: r.id, event_type: r.event_type || '',
    event_desc: r.event_desc || '',
    user_id: r.user_id || 'System',
    occurred_at: r.occurred_at || ''
  })),
  count: rows.length
};
return msg;

// Acknowledge HTTP request immediately
res.writeHead(200, { 'Content-Type': 'application/json' });
res.end(JSON.stringify({ ok: true }));

// Build shutdown event
msg.payload = {
    event_type: 'system-shutdown',
    event_desc: 'Jetpace EMS shut down',
    user_id: 'System'
};
return msg;
